const item = $input.first().json;

const storedConvId = item.chatwoot_conversation_id
  ? parseInt(String(item.chatwoot_conversation_id), 10)
  : null;

const conversation_id = storedConvId;
const pedido_codigo = String(item.pedido_codigo || ('#' + item.id));

// Formatear productos del carrito
let itemsText = '';
try {
  const items = typeof item.items === 'string'
    ? JSON.parse(item.items)
    : (Array.isArray(item.items) ? item.items : []);
  if (items.length > 0) {
    itemsText = items
      .map(i => `  • ${i.cantidad}x ${i.nombre}`)
      .join('\n');
  }
} catch(e) {}

let mensaje = `⏰ ¡Hola! Tu pedido *${pedido_codigo}* está esperándote 🛒\n`;

if (itemsText) {
  mensaje += `Llevas en tu carrito:\n${itemsText}\n\n`;
  mensaje += `¿Lo dejamos así o aprovechamos para agregarle algo más? 😊\n`;
  mensaje += `Cuéntanos qué se te antoja y te mostramos todo lo que tenemos disponible.`;
} else {
  mensaje += `¿Qué se te antoja hoy? Escríbenos y te contamos todas las opciones que tenemos para ti 😊`;
}

return [{
  json: {
    conversation_id,
    tiene_conversacion: conversation_id !== null,
    mensaje,
    pedido_codigo
  }
}];

// No hubo pedidos expirados en esta ejecución — noop silencioso
console.log('[Cron Expirar Pedidos] Sin pedidos que expirar.');
return [{ json: { total_expirados: 0 } }];

const item = $input.first().json;

const storedConvId = item.chatwoot_conversation_id
  ? parseInt(String(item.chatwoot_conversation_id), 10)
  : null;

const conversation_id = storedConvId;
const pedido_codigo = String(item.pedido_codigo || ('#' + item.id));

const mensaje = `Hola 👋 No tuvimos más actividad en tu pedido *${pedido_codigo}*, `
  + `así que entendemos que tu antojo puede esperar por ahora.\n\n`
  + `Cuando estés listo, cuéntanos qué se te apetece — `
  + `estaremos encantados de prepararlo para ti. ¡Hasta pronto! 😊`;

return [{
  json: {
    conversation_id,
    tiene_conversacion: conversation_id !== null,
    mensaje,
    pedido_codigo,
    telefono: String(item.telefono || '')
  }
}];
